// PORTFOLIO SHARE CARD — Final version
// • Format picker modal: PNG / JPEG / SVG
// • POST TO X: saves image first, then opens X with instructions to attach
// • Telegram / Copy Text
// • Privacy: blur amounts, anon mode
// ─────────────────────────────────────────────────────────────────────────────

import React, { FC, useState, useCallback, useMemo } from 'react';
import { BRAINS_LOGO } from '../constants';
import type { PortfolioSnapshot, SnapshotToken } from '../lib/supabase';

// ─── BRAINS LOGO — embedded as base64 so it always renders in SVG exports ──────
// This is images1st.jpg encoded inline. No CORS, no external requests.
const BRAINS_LOGO_B64 = 'data:image/jpeg;base64,';

// ─── STYLE INJECTION ──────────────────────────────────────────────────────────
