// ─── CANONICAL TIERS ──────────────────────────────────────────────────────────
const TIERS = [
  { min:0,         label:'UNRANKED',     icon:'○',  neon:'#a0bbcc' },
  { min:1,         label:'SPARK',        icon:'✦',  neon:'#bbddff' },
  { min:25_000,    label:'FLAME',        icon:'🕯️', neon:'#ffdd77' },
  { min:50_000,    label:'INFERNO',      icon:'🔥', neon:'#ffaa44' },
  { min:100_000,   label:'OVERWRITE',    icon:'⚙️', neon:'#ff8811' },
  { min:200_000,   label:'ANNIHILATE',   icon:'💥', neon:'#ff6622' },
  { min:350_000,   label:'TERMINATE',    icon:'⚡', neon:'#ff4411' },
  { min:500_000,   label:'DISINTEGRATE', icon:'☢️', neon:'#ff2277' },
  { min:700_000,   label:'GODSLAYER',    icon:'⚔️', neon:'#dd22ff' },
  { min:850_000,   label:'APOCALYPSE',   icon:'💀', neon:'#ff1155' },
  { min:1_000_000, label:'INCINERATOR',  icon:'☠️', neon:'#fffaee' },
];
const getTier = (pts: number) => {
  for (let i = TIERS.length - 1; i >= 0; i--) if (pts >= TIERS[i].min) return TIERS[i];
  return TIERS[0];
};

// ─── FORMATTERS ───────────────────────────────────────────────────────────────
const fmtUSD = (v: number) =>
  v >= 1_000_000 ? `$${(v/1e6).toFixed(2)}M` :
  v >= 1_000     ? `$${(v/1e3).toFixed(2)}K` :
  `$${v.toFixed(2)}`;
const fmtPct  = (v: number) => `${v >= 0 ? '+' : ''}${v.toFixed(2)}%`;
const fmtPts  = (n: number) =>
  n >= 1_000_000 ? `${(n/1e6).toFixed(2)}M` :
  n >= 1_000     ? `${(n/1e3).toFixed(1)}K` :
  n.toLocaleString();
const shortAddr = (a: string) => `${a.slice(0,5)}…${a.slice(-4)}`;
const todayStr  = () => new Date().toLocaleDateString('en-US',{month:'short',day:'numeric',year:'numeric'});

const COLORS = ['#ff8c00','#00d4ff','#bf5af2'];

// ─── TYPES ────────────────────────────────────────────────────────────────────
export interface PortfolioShareCardProps {
  totalUSD:       number | null;
  snapshotTokens: SnapshotToken[];
  snapshots:      PortfolioSnapshot[];
  walletAddress:  string | null;
  burnedTotal:    number;
  labWorkPts:     number;
  isMobile:       boolean;
}

type ExportFormat = 'png' | 'jpeg' | 'svg';

// ─── SVG CARD BUILDER — always works, no CORS issues ─────────────────────────
function buildSVGCard(opts: {
  totalUSD: number | null; change24h: number | null; change24hUSD: number | null;
  topHoldings: (SnapshotToken & { pct: number })[]; burnPts: number;
  burnTier: typeof TIERS[0]; walletAddr: string | null;
  blurAmounts: boolean; anonMode: boolean;
}): string {
  const { totalUSD, change24h, change24hUSD, topHoldings, burnPts, burnTier, walletAddr, blurAmounts, anonMode } = opts;
  const W = 840;
  const isUp   = (change24h ?? 0) >= 0;
  const chgClr = isUp ? '#00c98d' : '#ff4466';
  const addr   = anonMode ? 'ANONYMOUS' : walletAddr ? shortAddr(walletAddr) : 'PORTFOLIO';
  const date   = todayStr();

  // ── Layout constants ──────────────────────────────────────────────────────
  const TOP_BAR       = 4;
  const HEADER_H      = 96;   // top bar → divider line
  const VALUE_TOP     = 24;   // gap below divider before "TOTAL PORTFOLIO VALUE"
  const VALUE_H       = change24h !== null ? 90 : 60;  // value + optional 24h pill
  const SECTION_GAP   = 24;   // breathing room before each section divider
  const DIVIDER_H     = 18;   // divider line + label text
  const HOLDING_ROW_H = 54;   // height per holding row
  const BURN_H        = burnPts > 0 ? 64 : 0;  // burn rank block (label + value)
  const FOOTER_H      = 56;   // footer strip
  const BOT_BAR       = 3;

  // Build Y cursor top-down so nothing overlaps
  let y = TOP_BAR + HEADER_H;

  const valueY      = y + VALUE_TOP;
  y = valueY + VALUE_H;

  const holdingsDivY = y + SECTION_GAP;
  const holdingsLabelY = holdingsDivY + DIVIDER_H;
  const holdingsStartY = holdingsLabelY + 18;  // first row center
  y = holdingsStartY + topHoldings.slice(0,3).length * HOLDING_ROW_H;

  const burnDivY  = burnPts > 0 ? y + SECTION_GAP : 0;
  const burnLabelY = burnDivY + 18;
  const burnValueY = burnLabelY + 26;
  y = burnPts > 0 ? burnValueY + 22 : y;

  const footerY = y + SECTION_GAP;
  const H       = footerY + FOOTER_H + BOT_BAR;

  // ── Holding rows ──────────────────────────────────────────────────────────
  const holdingRows = topHoldings.slice(0,3).map((t, i) => {
    const rowY = holdingsStartY + i * HOLDING_ROW_H;
    const barW = Math.min(t.pct / 100 * 400, 400);
    return `
    <circle cx="52" cy="${rowY}" r="11" fill="${COLORS[i]}18" stroke="${COLORS[i]}40" stroke-width="1"/>
    <text x="52" y="${rowY+4}" text-anchor="middle" fill="${COLORS[i]}" font-family="monospace" font-size="9" font-weight="700">${i+1}</text>
    <text x="74" y="${rowY+5}" fill="${COLORS[i]}" font-family="monospace" font-size="13" font-weight="700">${t.symbol}</text>
    <rect x="148" y="${rowY-4}" width="${barW}" height="4" rx="2" fill="${COLORS[i]}" opacity="0.75"/>
    <text x="${W-32}" y="${rowY+5}" text-anchor="end" fill="#e0e8f0" font-family="monospace" font-size="12" font-weight="700">${blurAmounts ? '••••' : fmtUSD(t.usd)}</text>
    <text x="${W-32}" y="${rowY+18}" text-anchor="end" fill="#a0b8cc" font-family="monospace" font-size="11">${t.pct.toFixed(1)}%</text>`;
  }).join('');

  return `<svg xmlns="http://www.w3.org/2000/svg" width="${W}" height="${H}" viewBox="0 0 ${W} ${H}">
  <defs>
    <linearGradient id="topBar" x1="0" y1="0" x2="1" y2="0">
      <stop offset="0%"   stop-color="#ff4400"/>
      <stop offset="25%"  stop-color="#ff8c00"/>
      <stop offset="50%"  stop-color="#ffb700"/>
      <stop offset="75%"  stop-color="#00d4ff"/>
      <stop offset="100%" stop-color="#bf5af2"/>
    </linearGradient>
    <linearGradient id="botBar" x1="0" y1="0" x2="1" y2="0">
      <stop offset="0%"   stop-color="#bf5af2"/>
      <stop offset="25%"  stop-color="#00d4ff"/>
      <stop offset="50%"  stop-color="#ffb700"/>
      <stop offset="75%"  stop-color="#ff8c00"/>
      <stop offset="100%" stop-color="#ff4400"/>
    </linearGradient>
    <linearGradient id="valGrad" x1="0" y1="0" x2="0" y2="1">
      <stop offset="0%"   stop-color="#ffffff"/>
      <stop offset="100%" stop-color="#c0d8e8"/>
    </linearGradient>
    <pattern id="grid" x="0" y="0" width="24" height="24" patternUnits="userSpaceOnUse">
      <path d="M 24 0 L 0 0 0 24" fill="none" stroke="rgba(255,140,0,0.025)" stroke-width="0.5"/>
    </pattern>
    <clipPath id="logoClip"><circle cx="58" cy="60" r="24"/></clipPath>
    <clipPath id="footClip"><circle cx="44" cy="${footerY+28}" r="13"/></clipPath>
  </defs>

  <rect width="${W}" height="${H}" rx="20" fill="#07090f"/>
  <rect width="${W}" height="${H}" rx="20" fill="url(#grid)"/>

  <!-- Corner marks -->
  <path d="M18 36 L18 18 L36 18"                           fill="none" stroke="rgba(255,140,0,0.4)" stroke-width="1"/>
  <path d="M${W-36} 18 L${W-18} 18 L${W-18} 36"           fill="none" stroke="rgba(255,140,0,0.4)" stroke-width="1"/>
  <path d="M18 ${H-36} L18 ${H-18} L36 ${H-18}"           fill="none" stroke="rgba(0,212,255,0.3)" stroke-width="1"/>
  <path d="M${W-36} ${H-18} L${W-18} ${H-18} L${W-18} ${H-36}" fill="none" stroke="rgba(0,212,255,0.3)" stroke-width="1"/>

  <rect x="0" y="0"     width="${W}" height="4" rx="2" fill="url(#topBar)"/>
  <rect x="0" y="${H-3}" width="${W}" height="3"        fill="url(#botBar)"/>

  <!-- Header -->
  <circle cx="58" cy="60" r="30" fill="none" stroke="url(#topBar)" stroke-width="2.5"/>
  <circle cx="58" cy="60" r="24" fill="#1a0e00"/>
  <image href="${BRAINS_LOGO_B64}" x="34" y="36" width="48" height="48" clip-path="url(#logoClip)" preserveAspectRatio="xMidYMid slice"/>
  <text x="98" y="53" fill="#ff8c00" font-family="monospace" font-size="16" font-weight="900" letter-spacing="2">X1 BRAINS</text>
  <text x="98" y="70" fill="#7a98b4" font-family="monospace" font-size="11" letter-spacing="2">PORTFOLIO TRACKER · X1 BLOCKCHAIN</text>
  <rect x="${W-190}" y="42" width="170" height="26" rx="13" fill="rgba(255,255,255,0.03)" stroke="rgba(255,255,255,0.07)" stroke-width="0.5"/>
  <text x="${W-105}" y="59" text-anchor="middle" fill="#a0b8cc" font-family="monospace" font-size="11" letter-spacing="1">${anonMode ? '🕶 ' : ''}${addr}</text>
  <line x1="24" y1="92" x2="${W-24}" y2="92" stroke="rgba(255,255,255,0.04)" stroke-width="1"/>

  <!-- Value -->
  <text x="32" y="${valueY+14}" fill="#a0b8cc" font-family="monospace" font-size="12" letter-spacing="3">TOTAL PORTFOLIO VALUE</text>
  <text x="32" y="${valueY+64}" fill="url(#valGrad)" font-family="monospace" font-size="52" font-weight="900">${blurAmounts ? '••••' : (totalUSD !== null ? fmtUSD(totalUSD) : '—')}</text>

  ${change24h !== null ? `
  <rect x="32" y="${valueY+72}" width="230" height="27" rx="13.5" fill="${isUp ? 'rgba(0,201,141,0.1)' : 'rgba(255,68,102,0.1)'}" stroke="${isUp ? 'rgba(0,201,141,0.25)' : 'rgba(255,68,102,0.25)'}" stroke-width="0.5"/>
  <text x="50"  y="${valueY+90}" fill="${chgClr}" font-family="monospace" font-size="10">${isUp ? '▲' : '▼'}</text>
  <text x="66"  y="${valueY+90}" fill="${chgClr}" font-family="monospace" font-size="12" font-weight="700">${blurAmounts ? '••%' : fmtPct(change24h)}</text>
  ${change24hUSD !== null ? `<text x="152" y="${valueY+90}" fill="${chgClr}" font-family="monospace" font-size="11" opacity="0.75">(${blurAmounts ? '••••' : ((isUp?'+':'')+fmtUSD(change24hUSD))})</text>` : ''}
  <text x="240" y="${valueY+90}" fill="#a0b8cc" font-family="monospace" font-size="11">24h</text>
  ` : ''}

  <!-- Holdings -->
  <line x1="24" y1="${holdingsDivY}" x2="${W-24}" y2="${holdingsDivY}" stroke="rgba(255,255,255,0.05)" stroke-width="1"/>
  <text x="32"  y="${holdingsLabelY}" fill="#a0b8cc" font-family="monospace" font-size="12" letter-spacing="3">TOP HOLDINGS</text>
  ${holdingRows}

  <!-- Burn rank -->
  ${burnPts > 0 ? `
  <line x1="24" y1="${burnDivY}" x2="${W-24}" y2="${burnDivY}" stroke="rgba(255,255,255,0.05)" stroke-width="1"/>
  <text x="32"      y="${burnLabelY}" fill="#a0b8cc"         font-family="monospace" font-size="11" letter-spacing="3">BURN RANK</text>
  <text x="${W-32}" y="${burnLabelY}" text-anchor="end" fill="#a0b8cc" font-family="monospace" font-size="11" letter-spacing="3">LB POINTS</text>
  <text x="32"      y="${burnValueY}" fill="${burnTier.neon}" font-family="monospace" font-size="22" font-weight="900">${burnTier.icon} ${burnTier.label}</text>
  <text x="${W-32}" y="${burnValueY}" text-anchor="end" fill="${burnTier.neon}" font-family="monospace" font-size="24" font-weight="900">${blurAmounts ? '•••' : fmtPts(burnPts)}</text>
  ` : ''}

  <!-- Footer -->
  <rect x="0" y="${footerY}" width="${W}" height="${FOOTER_H}" fill="rgba(255,140,0,0.04)"/>
  <line x1="0" y1="${footerY}" x2="${W}" y2="${footerY}" stroke="rgba(255,255,255,0.05)" stroke-width="1"/>
  <circle cx="44" cy="${footerY+28}" r="13" fill="#1a0e00" stroke="rgba(255,140,0,0.3)" stroke-width="1"/>
  <image href="${BRAINS_LOGO_B64}" x="31" y="${footerY+15}" width="26" height="26" clip-path="url(#footClip)" preserveAspectRatio="xMidYMid slice"/>
  <text x="64" y="${footerY+20}" fill="#ff8c00" font-family="monospace" font-size="11" font-weight="700" letter-spacing="1.5">X1 BRAINS</text>
  <text x="64" y="${footerY+36}" fill="#a0b8cc" font-family="monospace" font-size="11" letter-spacing="2">x1brains.io</text>
  <rect x="${W/2-75}" y="${footerY+10}" width="150" height="22" rx="3" fill="rgba(0,201,141,0.08)" stroke="rgba(0,201,141,0.2)" stroke-width="0.5"/>
  <circle cx="${W/2-58}" cy="${footerY+21}" r="3.5" fill="#00c98d"/>
  <text x="${W/2-50}" y="${footerY+25}" fill="#00c98d" font-family="monospace" font-size="10" letter-spacing="1">ON-CHAIN VERIFIED</text>
  <text x="${W-32}" y="${footerY+20}" text-anchor="end" fill="#a0b8cc" font-family="monospace" font-size="11" letter-spacing="2">X1 BLOCKCHAIN</text>
  <text x="${W-32}" y="${footerY+36}" text-anchor="end" fill="#a0b8cc" font-family="monospace" font-size="11">${date}</text>
</svg>`;
}

// ─── RASTERIZE SVG → PNG or JPEG ─────────────────────────────────────────────
// Converts the SVG card string to a raster image via <img>+<canvas>.
// No html2canvas, no CORS, no DOM quirks — always works in every browser.
async function svgToRaster(svgString: string, fmt: 'png' | 'jpeg', scale = 2): Promise<Blob> {
  return new Promise((resolve, reject) => {
    // Parse dimensions from the SVG viewBox / width attributes
    const parser  = new DOMParser();
    const svgDoc  = parser.parseFromString(svgString, 'image/svg+xml');
    const svgEl   = svgDoc.documentElement;
    const w       = parseInt(svgEl.getAttribute('width')  || '840', 10);
    const h       = parseInt(svgEl.getAttribute('height') || '520', 10);

    // Encode SVG as a data URI — must be UTF-8 safe
    const encoded  = btoa(unescape(encodeURIComponent(svgString)));
    const dataUri  = `data:image/svg+xml;base64,${encoded}`;

    const img = new Image();
    img.onload = () => {
      const canvas  = document.createElement('canvas');
      canvas.width  = w * scale;
      canvas.height = h * scale;
      const ctx     = canvas.getContext('2d')!;

      // Fill background for JPEG (JPEG has no alpha channel)
      if (fmt === 'jpeg') {
        ctx.fillStyle = '#07090f';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
      }

      ctx.drawImage(img, 0, 0, canvas.width, canvas.height);

      const mime    = fmt === 'jpeg' ? 'image/jpeg' : 'image/png';
      const quality = fmt === 'jpeg' ? 0.93 : undefined;

      canvas.toBlob(
        blob => blob ? resolve(blob) : reject(new Error('Canvas toBlob returned null')),
        mime,
        quality,
      );
    };
    img.onerror = () => reject(new Error('SVG image failed to load'));
    img.src = dataUri;
  });
}

// ─── FORMAT PICKER MODAL ─────────────────────────────────────────────────────
const FormatPicker: FC<{
  onPick: (fmt: ExportFormat) => void;
  onClose: () => void;
  onTextOnly?: () => void;
  busy: boolean;
  forX?: boolean;
  forTelegram?: boolean;
}> = ({ onPick, onClose, onTextOnly, busy, forX, forTelegram }) => {
  const isContextual = forX || forTelegram;
  const platform     = forTelegram ? 'Telegram' : 'X';
  const formats: { fmt: ExportFormat; icon: string; label: string; desc: string; color: string; bg: string; border: string }[] = [
    { fmt:'png',  icon:'🖼️', label:'PNG',  desc:'Best quality\nTransparent bg',  color:'#00d4ff', bg:'rgba(0,212,255,.06)',  border:'rgba(0,212,255,.25)'  },
    { fmt:'jpeg', icon:'📸', label:'JPEG', desc:'Smaller file\nGreat for socials', color:'#00c98d', bg:'rgba(0,201,141,.06)',  border:'rgba(0,201,141,.25)'  },
    { fmt:'svg',  icon:'✏️', label:'SVG',  desc:'Always works\nScale to any size', color:'#bf5af2', bg:'rgba(191,90,242,.06)', border:'rgba(191,90,242,.25)' },
  ];

  return (
    /* Backdrop */
    <div
      onClick={onClose}
      style={{ position:'fixed', inset:0, zIndex:99998, background:'rgba(0,0,0,.75)', backdropFilter:'blur(6px)', display:'flex', alignItems:'center', justifyContent:'center', padding:'20px' }}
    >
      {/* Modal */}
      <div
        onClick={e => e.stopPropagation()}
        style={{ background:'linear-gradient(145deg,#0d1520,#0a1018)', border:'1px solid rgba(255,140,0,.2)', borderRadius:18, padding:'24px', maxWidth:440, width:'100%', animation:'psc-modal-in .25s ease both', position:'relative' }}
      >
        {/* Top accent */}
        <div style={{ position:'absolute', top:0, left:0, right:0, height:2, background:'linear-gradient(90deg,#ff4400,#ff8c00,#ffb700,#00d4ff,#bf5af2)', borderRadius:'18px 18px 0 0' }} />

        {/* Header */}
        <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:6 }}>
          <div>
            <div style={{ fontFamily:'Orbitron,monospace', fontSize:13, fontWeight:900, color:'#e0e8f0', letterSpacing:2 }}>
              {isContextual ? `SAVE IMAGE & POST TO ${platform.toUpperCase()}` : 'CHOOSE FORMAT'}
            </div>
            {isContextual && (
              <div style={{ fontFamily:'Sora,sans-serif', fontSize:10, color:'#5a7a90', marginTop:4, lineHeight:1.5 }}>
                {forTelegram
                  ? 'Save your card then attach it in Telegram — tap the paperclip icon in the share dialog.'
                  : "X's API doesn't allow direct image uploads from web apps. Save your card, then attach it manually when X opens."
                }
              </div>
            )}
          </div>
          <button onClick={onClose} style={{ background:'none', border:'none', color:'#4a6070', cursor:'pointer', fontSize:22, lineHeight:1, padding:'0 4px', marginLeft:8 }}>×</button>
        </div>

        {isContextual && (
          <div style={{ marginBottom:14 }}>
            <div style={{ display:'flex', alignItems:'flex-start', gap:8, padding:'10px 12px', background:'rgba(255,183,0,.06)', border:'1px solid rgba(255,183,0,.18)', borderRadius:8, marginBottom:10 }}>
              <span style={{ fontSize:14, flexShrink:0, marginTop:1 }}>💡</span>
              <div style={{ fontFamily:'Sora,sans-serif', fontSize:10, color:'#8aaa7a', lineHeight:1.6 }}>
                {forTelegram ? (
                  <><span style={{ color:'#ffb700', fontWeight:600 }}>How to attach:</span> After Telegram opens, tap the paperclip / attachment icon and select the saved card from your downloads.</>
                ) : (
                  <><span style={{ color:'#ffb700', fontWeight:600 }}>How to attach:</span> After X opens, click the image icon in the composer and select the saved card from your downloads.</>
                )}
              </div>
            </div>
            <button
              onClick={() => onTextOnly?.()}
              style={{ width:'100%', padding:'9px 0', borderRadius:8, cursor:'pointer', background:'rgba(255,255,255,.03)', border:'1px solid rgba(255,255,255,.1)', fontFamily:'Orbitron,monospace', fontSize:8, fontWeight:700, color:'#6a8ea8', letterSpacing:1.5, transition:'all .2s' }}
            >
              💬 SKIP IMAGE — POST TEXT ONLY
            </button>
          </div>
        )}

        {/* Format buttons */}
        <div style={{ display:'flex', gap:10, marginBottom:isContextual ? 16 : 0 }}>
          {formats.map(({ fmt, icon, label, desc, color, bg, border }) => (
            <button
              key={fmt}
              disabled={busy}
              className="psc-fmt-btn"
              style={{ color, background:bg, borderColor:border }}
              onClick={() => onPick(fmt)}
            >
              <span style={{ fontSize:22 }}>{icon}</span>
              <div style={{ fontFamily:'Orbitron,monospace', fontSize:11, fontWeight:900, letterSpacing:1.5 }}>{label}</div>
              <div style={{ fontFamily:'Sora,sans-serif', fontSize:9, color:'#5a7a90', textAlign:'center', lineHeight:1.5, whiteSpace:'pre-line' }}>{desc}</div>
            </button>
          ))}
        </div>

        {busy && (
          <div style={{ fontFamily:'Orbitron,monospace', fontSize:9, color:'#ff8c00', letterSpacing:1, textAlign:'center', marginTop:12, animation:'psc-in .2s ease both' }}>
            ⟳ Generating…
          </div>
        )}
      </div>
    </div>
  );
};

// ─── CARD CANVAS (inline styled — gets screenshotted) ─────────────────────────
